var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"거기! 위험하니까 엎드리세요!","JPN":"そこ！　危ないのでうつ伏せになってください！","ENG":"Hey, you! Get down!","TWN":"喂！危險，快趴下！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"파...... 파이어 볼!","JPN":"ファ……ファイヤボール！","ENG":"F-Fireball!","TWN":"火……火焰球！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"괜찮으세요? 다친 데는 없고요?","JPN":"大丈夫ですか？　怪我はありませんか？","ENG":"Are you alright? Not hurt or anything?","TWN":"妳沒事吧？沒有受傷吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아, 덕분에요. 보시는 대로 멀쩡하답니다.","JPN":"あ、おかげさまで助かりました。見てのとおり無事です。","ENG":"Oh, I'm fine. Thanks to you.","TWN":"多虧了你，我沒有受傷。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"다행이다......","JPN":"よかった……","ENG":"Thank goodness...","TWN":"真是萬幸……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저쪽으로 가면 대피소가 있을 거예요. 침식체가 더 나타나기 전에 어서 가세요.","JPN":"あそこに行けば避難所があるはずです。侵食体がもっと現れる前に早く行ってください。","ENG":"You'll find a shelter over there. Please get to safety before more C.O.s appear.","TWN":"那邊有避難所，趁侵蝕體還沒出現，快去躲一躲吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"고마워요. 이 도시 분들은 다들 친절하네요.","JPN":"ありがとう。この都市の方々はみんな親切ですね。","ENG":"Thank you. Everyone in this city is so kind.","TWN":"謝謝，這個城市的人都很熱情。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그런데, 도와 주신 분의 이름은 어떻게 되시죠?","JPN":"ところで、私を助けてくださったあなたのお名前は？","ENG":"By the way, may I ask for your name?","TWN":"請問，您叫什麼名字？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아, 전 유나에요. 유나 스프링필드.","JPN":"あ、私はユナです。ユナ・スプリングフィールド。","ENG":"Oh, I'm Yuna. Yuna Springfield.","TWN":"啊，我叫尤娜。尤娜·斯普林菲爾德。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그래요? 스프링필드라......?","JPN":"そうですか。スプリングフィールド……？","ENG":"Oh? Springfield?","TWN":"這樣啊？斯普林菲爾德……？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"응? 혹시 절 아세요?","JPN":"ん？　もしかして、私を知ってるんですか？","ENG":"Huh? Do you know me?","TWN":"嗯？你認識我嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아뇨. 예전에 알던 분과 비슷한 이름이라서요.","JPN":"いいえ。知り合いの方と似たような名前だったので。","ENG":"No. Your name just reminds me of someone I once knew.","TWN":"不認識，只是名字跟我認識的人有點像。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그보다 전 대피소로 가기 어렵겠어요. 꼭 들러야 할 곳이 있거든요.","JPN":"それより、私は避難所には行けません。行かないといけない場所がありますから。","ENG":"Anyway, I'm afraid I won't be able to reach the shelter in time. There's a place I must stop by first.","TWN":"看來我不能去避難所了，因為我得去一個地方。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"위, 위험해요! 침식체가 어디 숨어 있을지 모르는데!","JPN":"あ、危ないですよ！　侵食体がどこに潜んでいるかわからないのに！","ENG":"B-but it's too dangerous! There's no telling where the C.O.s are hiding!","TWN":"太危險了！侵蝕體也不知道躲在哪裡！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"걱정은 고맙지만, 전 이번 할로윈 축제에 참가할 인형 퍼레이드의 책임자라서요.","JPN":"気持ちはありがたいのですが、私は今回のハロウィンに参加する人形パレードの責任者なんです。","ENG":"I appreciate your concern, but I'm in charge of the puppet parade for this Halloween festival.","TWN":"我知道妳在擔心什麼，但我是這次萬聖節慶典的木偶遊行表演的負責人。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"공연 준비를 하려면 제 인형들이 무사한지 확인해야 돼요.","JPN":"パレードの準備をするために私の人形たちが無事なのか確認しないと。","ENG":"I have to see if my puppets are okay if I want to prepare for the show.","TWN":"所以我得去查看我的木偶是否安全。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"인형 퍼레이드요......?","JPN":"人形パレードですか……？","ENG":"The puppet parade?","TWN":"木偶遊行表演……？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아! 설마 크로넨워스 인형극단 분이세요?! 저 축제 광고에서 본 적 있어요!","JPN":"あ！　もしかしてクロネンワース人形劇団の方なんですか？\\n私、お祭りのポスターで見たことあります！","ENG":"Oh! Are you from the Cronenworth Puppet Troupe? I saw you in the festival ads!","TWN":"啊！你是克羅尼溫斯木偶劇團的？！我好像在慶典廣告看到過！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"네. 그렇답니다.","JPN":"はい。そうです。","ENG":"That's right.","TWN":"嗯，是的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저 거기 인형극 엄청 좋아해요! 할머니 몰래 보러 가기도 했는데!","JPN":"私、クロネンワースの人形劇が大好きなんです！　お婆ちゃんに内緒で見に行ったこともありますよ！","ENG":"Oh, I love your shows! I even snuck out of the house once without telling my grandma!","TWN":"我很喜歡木偶戲呢！我還瞞著奶奶偷偷去看過！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아, 아니, 이게 아니라......","JPN":"い、いや、そうじゃなくて……","ENG":"Oh, um... What I meant was...","TWN":"啊，不不，不對……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"혼자 다니시면 위험할 거예요. 제가 도와 줄 사람을 불러 드릴게요.","JPN":"一人で出歩いたら危ないですよ。私、手伝ってくれる人を呼んできますね。","ENG":"It's too dangerous for you to go around by yourself right now. I'll get someone to help you.","TWN":"你現在自己亂逛很危險，我給你找一個可以幫你的人吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"도와 줄 사람이요?","JPN":"手伝ってくれる人ですか？","ENG":"Someone to help me?","TWN":"幫我的人？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"침식체들의 눈에 띄면 위험합니다! 제가 만든 얼음 방벽 뒤로 피하세요!","JPN":"侵食体の目につくと危ないですわ！　私が作った氷の防壁の後ろに逃げてください！","ENG":"Don't let the C.O.s see you! Hide behind the wall of ice I've created!","TWN":"被侵蝕體發現了可是很危險的！快躲到我的寒冰屏障後面！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"하하. 트릭 오어 트릿이다. 자식들아.","JPN":"はは。トリック・オア・トリートだ。野郎ども。","ENG":"Hah hah! Trick or treat, you bastards!","TWN":"哈哈，不吃糖就搗蛋啊，你們這群傢伙。"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_CHAINSAW_START"},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"크르르...... 크르르......","JPN":"グルル……グルル……","ENG":"Grr... Grr...","TWN":"吼……吼……"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"뭐? 사탕을 주겠다고?","JPN":"何だと？　キャンディをくれるって？","ENG":"What's that? You've got candy for me?","TWN":"什麼？要給我糖？"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"크르르! 크르크르!","JPN":"グルル！　グルル！","ENG":"Grr! Grr!","TWN":"吼啊！吼吼！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"필요없어!","JPN":"いらない！","ENG":"No thanks!","TWN":"糖就免了！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"끼이이잉!!","JPN":"キィイイン！？","ENG":"*Whimper*","TWN":"吱嗚嗚嗚！!"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SLASH_BIG"},{"id":"L44_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저기요! 두 분!","JPN":"あ！　二人とも！","ENG":"Hey, you two!","TWN":"喂！兩位！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"응? 한창 재미 보던 중인데 뭐야?","JPN":"うん？　いいところだったのに、何だ？","ENG":"Huh? I was having so much fun... What do you want?","TWN":"嗯？正玩得有趣呢，幹嘛？"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"카페의 마녀 분이시군요. 무슨 일이죠?","JPN":"カフェの魔女さんですね。どうしました？","ENG":"You're the witch from the cafe. What is it?","TWN":"原來是咖啡店的魔女啊，怎麼了？"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저어, 여기 이 분께서 가야 할 곳이 있다는데 호위를 좀 해 주시면 안 될까요?","JPN":"あの、この方が立ち寄りたい場所があるそうなんです。護衛を頼んでもいいですか？","ENG":"Um, this lady here needs to get somewhere. Could you two maybe escort her?","TWN":"他要去一個地方，能不能拜託你保護他過去？"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"그 정도야 특별히 무리는 아닙니다만......","JPN":"それぐらいは問題はないですが……","ENG":"Well, that won't be difficult, but...","TWN":"雖然不是什麼難事……"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"하아? 내가 왜 그래야 하는데?","JPN":"は？　なんでアタシが護衛しなきゃいけないんだ？","ENG":"Huh? Why should I do that?","TWN":"蛤？我為什麼要聽妳的話？"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그, 그게......","JPN":"そ、それは……","ENG":"W-well...","TWN":"那、那個……"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아, 맞다! 올해 축제의 퍼레이드를 책임지는 분이래요!","JPN":"あ、そうだ！　今年の人形パレードの責任者だそうです！","ENG":"Oh, that's right! She's in charge of the parade this year!","TWN":"啊，對了！他是今年慶典遊行表演的負責人！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이 분에게 무슨 일이 생기면 축제가 제대로 안 열릴지도 몰라요.","JPN":"この方にもし何かあったら、お祭りがうまくいかないかもしれません。","ENG":"If something happens to her, the festival might not go as planned.","TWN":"如果他出事了，就辦不成慶典了。"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"두 분 모두 축제 때 열릴 코스튬 경연 대회에 참가하려고 옷을 주문하셨던 거 맞죠?","JPN":"二人もお祭りで開催されるコスチュームコンテストに参加するために服を注文したんですよね？","ENG":"Both of you ordered your costumes to participate in the costume contest at the festival, right?","TWN":"兩位是不是訂了慶典期間舉辦的扮裝大會的衣服？"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"아, 아뇨. 전 대회에 참가할 생각은 없었는데......","JPN":"い、いえ。私は別に参加するつもりでは……","ENG":"N-no, I wasn't exactly planning on joining the contest...","TWN":"沒、沒有。我沒想過要參加大賽……"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"뭐야, 그런 거였어?","JPN":"何だ、そういうことか。","ENG":"Oh, is that what's going on?","TWN":"什麼？這樣啊。"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"그런 중요한 일이면 진즉 말해야지. 가자.","JPN":"そんな大事なことは早く言えよ。行こう。","ENG":"Why didn't you say so?! Let's go.","TWN":"這麼重要的事，怎麼不早說，走吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"당신 뭘 마음대로 결정하는 거죠? 이봐요!","JPN":"あなた、何を勝手に決めてるんです？　ちょっと！","ENG":"Hey, you don't get to decide for the both of us. Hey!","TWN":"妳怎麼自己隨便決定啊？喂！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"다, 다행이다! 도와 주시겠대요!","JPN":"よ、よかった！　手伝ってくれるみたいです！","ENG":"Th-thank goodness! They're going to help!","TWN":"幸、幸好！她們願意幫你！"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"얼른 가요. 인형들이 망가지면 큰일이잖아요.","JPN":"早く行きましょう。人形たちが壊れたら大変ですよね。","ENG":"Let's go. We wouldn't want your puppets to get damaged.","TWN":"快去吧，木偶壞了就不好了。"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"후훗. 네. 서둘러야겠어요.","JPN":"ふふっ、はい。急ぎましょう。","ENG":"Hah hah, of course. Let's hurry.","TWN":"哈哈，嗯。我趕快去看看。"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그런데 참...... 재미있는 분들이네요.","JPN":"ところで、本当に……面白い方たちですね。","ENG":"I must say though... You're all very interesting.","TWN":"她們真是……有趣啊。"},"stage":{"bg":"CITY_CENTER1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};